mapper.select:
SELECT p.id AS pid, p.problem_id AS problemId, p.title AS title, COALESCE(p.difficulty_rating, 1500) AS difficulty FROM problem p LEFT JOIN user_acproblem uap ON uap.uid = #{uid} AND uap.pid = p.id
uap.id IS NULL AND p.auth = 1 AND (p.is_group IS NULL OR p.is_group = 0)
AND p.id != #{excludePid}
ORDER BY ABS(COALESCE(p.difficulty_rating, 1500) - #{target}) ASC, p.id ASC LIMIT #{limit}
